{"path":"/data/projects/emmy/packages/emmy-telemetry/src/index.ts","binary":false,"lines":"dee593bd  // @emmy/telemetry — Phase 3 Plan 03-02 dual-sink body (D-06).
a2c23396  //
9cfb3c79  // emitEvent's signature is signature-stable from the Phase 2 Wave-0 stub
5ba33cb6  // (Phase 2 D-01: "empty telemetry stub now > telemetry-retrofit-workspace
cb55f11c  // later"). Every existing call site in @emmy/provider, @emmy/tools, and
1b86a657  // @emmy/ux keeps compiling unchanged.
a2c23396  //
995e6d65  // Dual-sink contract (RESEARCH §Pattern 3):
cf2c0fb8  //   - JSONL authoritative (appendJsonlAtomic; for records > PIPE_BUF fall
91a2e1d5  //     back to writeJsonAtomic tempfile+rename shape per Pattern A risk note).
1a5a7458  //     JSONL write never propagates fs errors upward — logs to stderr and
3665636a  //     continues so the agent loop is not blocked on disk IO.
28a375d3  //   - OTLP best-effort (tracer.startSpan + setAttribute + end). OTLP failure
f1d738e5  //     never propagates; JSONL remains authoritative. Exceptions during the
ba0621af  //     tracer path are swallowed per D-06.
a2c23396  //
b65ce910  // Profile stamp semantics:
2f6059ef  //   Every record's top-level `profile` key (if present) is flattened into
a9dd8463  //   emmy.profile.* span attributes AT emitEvent time. Additionally, the
f4af7845  //   EmmyProfileStampProcessor installed in otel-sdk.ts auto-stamps those
9b7aa630  //   same attrs on EVERY span started via the global Tracer (including spans
593c77e0  //   created by downstream code paths that do not go through emitEvent). The
e5623822  //   two mechanisms are redundant by design — per-event stamping keeps the
39d4e78f  //   JSONL record self-describing; processor stamping catches spans created
916a21a6  //   outside the emitEvent path (e.g. HARNESS-09 chat spans in Plan 03-03).
e3b0c442  
2aaf35ef  import { appendJsonlAtomic, writeJsonAtomic } from "./atomic-append";
6adda81d  import { getTelemetryContext } from "./session-context";
e3b0c442  
961c36d7  export interface TelemetryRecord {
7eb351a1  	event: string;
551d5cfd  	ts: string;
25ee6d94  	profile?: { id: string; version: string; hash: string };
f4d0f826  	[k: string]: unknown;
d10b36aa  }
e3b0c442  
ffc22698  // Linux PIPE_BUF. Writes up to this size are atomic with respect to
c418def3  // concurrent appenders sharing the fd; past this size we fall back to
405bc130  // writeJsonAtomic (tempfile + rename).
053ea88f  const PIPE_BUF = 4096;
e3b0c442  
f190119b  export function emitEvent(record: TelemetryRecord): void {
4e4a00fd  	const ctx = getTelemetryContext();
d7e597ab  	if (!ctx.enabled) return;
e3b0c442  
1d4312e1  	// --- JSONL authoritative (D-06) ---
8410fdf7  	if (ctx.jsonlPath) {
131bbee0  		try {
d94bf190  			const serialized = JSON.stringify(record);
45cb802b  			if (serialized.length + 1 > PIPE_BUF) {
b8d7a249  				writeJsonAtomic(ctx.jsonlPath, record);
ba73d2a4  			} else {
c18e9d22  				appendJsonlAtomic(ctx.jsonlPath, record);
4ffaefcc  			}
6041208b  		} catch (err) {
7a020f71  			// JSONL write failure must never block the agent loop; log to stderr
c881e2bc  			// so the operator has a surface for diagnosing lost events (same
a772dfd3  			// contract as Phase 1 diagnostic bundle best-effort writes).
2475dbcb  			console.error(
8728e513  				`[emmy/telemetry] JSONL append failed - event lost: ${err instanceof Error ? err.message : String(err)}`,
cdf704fc  			);
3713bbfd  		}
a32a3bb7  	}
e3b0c442  
efe382d5  	// --- OTLP best-effort (D-06) ---
49ed934c  	if (ctx.tracer) {
131bbee0  		try {
de2e5f0d  			const spanName = spanNameFor(record.event);
022ba76a  			const span = ctx.tracer.startSpan(spanName);
bddb3c5e  			try {
0b6a53a7  				for (const [k, v] of Object.entries(record)) {
32bea36f  					if (k === "event" || k === "ts") continue;
07dd3a66  					if (k === "profile" && v && typeof v === "object") {
455709fa  						for (const [pk, pv] of Object.entries(v as Record<string, unknown>)) {
ed02ebdd  							span.setAttribute(`emmy.profile.${pk}`, coerceAttr(pv));
49be74c7  						}
fdc69352  						continue;
0ba026ff  					}
2ce451b8  					span.setAttribute(`emmy.${k}`, coerceAttr(v));
0812d29f  				}
972e98eb  			} finally {
cbe25865  				span.end();
4ffaefcc  			}
06518044  		} catch {
e7e56540  			// OTLP failure accepted as best-effort (D-06). No console noise —
c2f3a77e  			// the boot banner already surfaced "JSONL-only" if Langfuse is
fb24e5db  			// unreachable. Per-event failures in the happy path are rare and
8365ab89  			// would spam stderr if logged here.
3713bbfd  		}
a32a3bb7  	}
d10b36aa  }
e3b0c442  
8d64a30d  /**
b1c2ec36   * Map emitEvent's `event` string (e.g. "session.sp_ok.pass") to an OTel span
1ef17e0b   * name in the emmy.* namespace. Keeps span names structurally parallel to
0a3527c5   * JSONL event names so a Langfuse-UI reader and a JSONL grep return identical
16b660a7   * result sets.
533a9f11   */
9f01153c  function spanNameFor(event: string): string {
c2c27ddc  	return `emmy.${event}`;
d10b36aa  }
e3b0c442  
8d64a30d  /**
7935d34c   * Coerce a TelemetryRecord attribute value to an OTel span attribute value.
d2706271   * OTel attrs accept string | number | boolean | array-thereof; we narrow to
fd35cc51   * the scalars and JSON-stringify anything else. Null / undefined -> "".
533a9f11   */
0bd5bb43  function coerceAttr(v: unknown): string | number | boolean {
ecf96d00  	if (v == null) return "";
1142aec2  	if (typeof v === "string" || typeof v === "number" || typeof v === "boolean") return v;
debaf31e  	try {
c0fa8617  		return JSON.stringify(v);
caf79c21  	} catch {
e4c86221  		return String(v);
a32a3bb7  	}
d10b36aa  }
e3b0c442  
c87d905e  // Re-exports so downstream callers don't need to know the internal module
155b3f5d  // layout. pi-emmy.ts uses: initOtel + shutdownOtel + resolveTelemetryEnabled +
d940addc  // configureTelemetry. Tests additionally use resetTelemetryContext.
011c0222  export { configureTelemetry, getTelemetryContext, resetTelemetryContext } from "./session-context";
dfc90908  export { appendJsonlAtomic, writeJsonAtomic } from "./atomic-append";
db8f2459  export { initOtel, shutdownOtel, resolveTelemetryEnabled } from "./otel-sdk";
56288109  export {
ab309834  	EmmyProfileStampProcessor,
8c63f9c5  	swapSpanProcessor,
25092677  	type ProfileStampAttrs,
eb2a3808  } from "./profile-stamp-processor";
f8474aab  // Phase 4 Plan 04-04 (HARNESS-08 / D-12) — per-turn variant/role context
70b6aafd  // read by profile-stamp-processor.onStart and populated by
6c9293fb  // pi-emmy-extension.ts's before_provider_request handler.
56288109  export {
26829ad7  	setCurrentTurnRoleContext,
6920754b  	clearCurrentTurnRoleContext,
25174464  	getCurrentTurnRoleContext,
bc8079a8  	type TurnRoleContext,
6e4141f7  } from "./turn-role-context";
e3b0c442  
750b0274  // Plan 03-06 — UX-03 offline audit pure functions + D-26 LOOPBACK_HOSTS.
7c77ebf0  // Plan 03.1-02 D-36 — SEARXNG_LOOPBACK_PORT + classifyEgressHost.
56288109  export {
a8ddf4e3  	auditToolRegistry,
3fc2cb8f  	auditWebFetchUrl,
cb239de7  	classifyEgressHost,
2a0dfec8  	LOOPBACK_HOSTS,
eaa24a97  	SEARXNG_LOOPBACK_PORT,
fab49acf  	type EmmyToolRegistration,
d94b4ed7  	type OfflineAuditResult,
564160f9  } from "./offline-audit";
e3b0c442  
d19a1e0d  // Plan 03-05 — lived-experience rating corpus (TELEM-02 + TELEM-03).
56288109  export {
93884a23  	FeedbackSchemaError,
70810236  	FeedbackNotFoundError,
de009fee  	validateRow,
a8fe4b6d  	type FeedbackRow,
ec28297b  } from "./feedback-schema";
56288109  export {
6c5a168c  	appendFeedback,
61b2e4ea  	readFeedback,
ee35db36  	updateFeedback,
d8e62be5  	upsertFeedback,
0ebf0240  	defaultFeedbackPath,
b186857e  } from "./feedback";
abd64594  export { TurnTracker, type TurnMeta } from "./turn-tracker";
2d1c17aa  export { exportHfDataset, type ExportResult, type ExportOpts } from "./hf-export";
e3b0c442  
361adbf7  export const PACKAGE_VERSION = "0.1.0";
